+const ALLOWED_SAME_ORIGIN_DOMAINS = [
+  "youtube.com",
+  "vimeo.com",
+  "figma.com",
+];
+
+export const getEmbeddableSandbox = (
+  element: ExcalidrawElement,
+  link: string | null,
+) => {
+  const baseSandbox = "allow-scripts allow-forms allow-popups allow-presentation";
+  
+  if (!link) {
+    return baseSandbox;
+  }
+
+  try {
+    const url = new URL(link);
+    const domain = url.hostname.replace(/^www\./, "");
+    if (ALLOWED_SAME_ORIGIN_DOMAINS.includes(domain)) {
+      return `${baseSandbox} allow-same-origin`;
+    }
+  } catch {
+    // ignore
+  }
+
+  return baseSandbox;
