+
+function isObject(obj) {
+    return (typeof obj === 'object') && (obj.constructor === Object);
+}
+
+function isNumber(obj) {
+    return (typeof obj === 'number') && (obj.constructor === Number);
+}
+
+function isArray(obj) {
